            }
        }
        return dp[rows - 1][cols - 1];
    }
}

class Solution {
    public int minimumTotal(List<List<Integer>> triangle) {
        int n = triangle.size();
        int[] dp = new int[n];
        List<Integer> lastRow = triangle.get(n - 1);
        for (int i = 0; i < n; i++) dp[i] = lastRow.get(i);

        for (int row = n - 2; row >= 0; row--) {
            List<Integer> current = triangle.get(row);
            for (int i = 0; i <= row; i++) {
                dp[i] = current.get(i) + Math.min(dp[i], dp[i + 1]);
            }
        }
        return dp[0];
    }
}

class Solution {
    public int minFallingPathSum(int[][] matrix) {
        int n = matrix.length;
        int[] prev = matrix[0].clone();
        for (int r = 1; r < n; r++) {
            int[] current = new int[n];
            for (int c = 0; c < n; c++) {
                int best = prev[c];
                if (c > 0) best = Math.min(best, prev[c - 1]);
                if (c < n - 1) best = Math.min(best, prev[c + 1]);
                current[c] = matrix[r][c] + best;
            }
            prev = current;
        }
        int result = Integer.MAX_VALUE;
        for (int val : prev) result = Math.min(result, val);
        return result;
    }
}

